import base64, os
files = {"src/contexts/AppContext.tsx": "", "src/pages/AdminPage.tsx": "", "src/pages/EditListing.tsx": "", "src/pages/CreateListing.tsx": "", "src/pages/Dashboard.tsx": "", "src/pages/SearchPage.tsx": "", "src/pages/ProfilePage.tsx": "", "src/pages/ListingDetail.tsx": "", "src/pages/MessagesPage.tsx": "", "src/pages/LoginPage.tsx": "", "src/pages/RegisterPage.tsx": "", "src/pages/RedefinirSenhaPage.tsx": "", "src/pages/PrivacidadePage.tsx": "", "src/pages/TermosPage.tsx": "", "src/components/ReviewSection.tsx": "", "src/components/ChatButton.tsx": "", "src/components/TermosModal.tsx": ""}

for path, b64 in files.items():
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'w', encoding='utf-8') as f:
        f.write(base64.b64decode(b64).decode('utf-8'))
    print(f'OK: {path}')
print('Todas as correcoes aplicadas!')
